INSERT INTO search_anchors (slug, city, radius_miles, status, last_batch_at, next_batch_after, notes, ring, position) VALUES ('tacoma-wa-25mi', 'Tacoma, WA', 25, 'in_progress', '2026-05-08', '2026-06-07', 'Batch 4 (2026-05-08): 34 rows pulled across 5 sources — 10 Mountaineers Tacoma Branch (full per-session sweep, Sarah Holt''s day camps + 2 teen overnight adventures, all at 2302 N 30th St plus Exit 38/Point Defiance field trips), 7 Sound Life Day Camp Tacoma (themed weeks Jun 22-Aug 7 at 1301 S Baltimore St 98465), 5 Wolf Camp Puyallup (Clark''s Creek Park + Blue Skye Farm wilderness/herbology weeks), 7 i9 Sports leagues (Office 426 Puyallup at Heritage Rec Center + Rogers HS, Office 489 Federal Way Todd Beamer HS, Kent Kentwood HS in Covington), 5 Breakthrough Basketball (Tacoma Bellarmine Prep + Auburn Fieldhouse USA grades 3-12). Spring 2026 Federal Way leagues already mid-season (start 4/25, end 6/6) but accepted as still-open. New permanent skips added: tacomasummercamps.com (aggregator) and hisawyer.com (Sawyer registration backend). New stale_listings: aw.org (Annie Wright Summer@AW Sawyer schedules not populated yet, recheck after content update) and nwfilmcamp.com (Tacoma page header reads "coming soon", dates listed don''t fall on Mon-Fri in 2026). New blocked: piercecountywa.gov (desktop URL piercecountywa.gov/4881/CampsClinics auto-redirects to mobile newsflash). Carry-over from Batch 3 still open: parkstacoma.gov (~200 remaining), penmetparks.org (188 still gated, try sitemap next), auburnwa.gov (~120 unspecified-location camps), Puyallup specialty camps weekly drill-down, school district summer programs, Skyhawks via partner portals, Lakewood club leagues, kentwa.gov entry-point. After those, Ring 1 Anchor 2 (Seattle, WA 25mi) becomes priority.', 1, 0) ON CONFLICT(slug) DO UPDATE SET city=excluded.city, radius_miles=excluded.radius_miles, status=excluded.status, last_batch_at=excluded.last_batch_at, next_batch_after=excluded.next_batch_after, notes=excluded.notes, ring=excluded.ring, position=excluded.position, updated_at=datetime('now');
