INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('parkstacoma.gov', 'Metro Parks Tacoma', 'tacoma-25mi', '2026-05-06', 'partial', 17, '2026-05-20', 'Batch 3 (2026-05-06): pulled 7 more sessions at NEW verified venues STAR Center (3873 S 66th St), Eastside CC (1721 E 56th St), People''s CC (1602 MLK Jr Way). 211 total camp results in ActiveNet catalog. Wainwright Intermediate and Heritage Hilltop MS venues not yet address-verified (TPS school pages 404). Norpoint and Heidelberg already pulled in prior batches. Cumulative: 17 sessions across all batches.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('cityofpuyallup.org', 'City of Puyallup Parks and Recreation', 'tacoma-25mi', '2026-05-06', 'camps_extracted', 10, '2026-06-05', 'Camp Yougottawanna all 10 weekly sessions Jun 22 - Aug 28 at Memorial Center (601 N Meridian Puyallup), ages 5-12, $190-$235/wk. All weeks 90/90 full with empty waitlists, status set to waitlist. Registration via rec1.com/WA/Puyallup-Parks-Recreation/catalog. Specialty camps (AI & Robotics 4 sessions, Bricks 4 Kidz 4, Dance 3, Parkour 2, Art 6) noted but not pulled this run — descriptions on rec1 are aggregated by program rather than per-week, would need to drill into each program for individual session dates. Worth a focused recheck for those specialty camps.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('auburnwa.gov', 'City of Auburn Parks Arts & Recreation', 'tacoma-25mi', '2026-05-06', 'partial', 5, '2026-06-05', 'Workaround found: ActiveNet URL pattern `apm.activecommunities.com/auburnwa/Activity_Search/<slug>/<id>` resolves directly without session context (DIFFERENT from PenMet''s broken /detail/<id> pattern). Pulled 5 sessions: 3 teen Adventure Camps (Hit the Road Jul 20-24, Trekkin'' Teens Aug 3-7, So Far Away! Aug 17-21, all $335/$422 ages 11.5-15) and 2 theatre camps (Hundred Acre Adventures Jul 27-31 ages 5-7, Disney Creative Drama Aug 10-14 ages 8-11, both $250/$312). All pulled rows venue at 910 9th St SE Auburn 98002 (Les Gove Park / Teen Center / Community Center complex — confirmed via direct browsing). 125 total ActiveNet camps; ~120 still need address verification per detail page (most lack explicit "Activity location" field; only the Les Gove–venued rows are address-verified so far). PROMPT-INJECTION FLAG: "Stop Claude" appeared on auburnwa.gov 404 footer + ActiveNet detail page footer — same untrusted-content treatment as ymcapkc.org. Mix & Match camps span Les Gove + offsite Cedar Lanes Bike Park transports.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('golutes.com', 'PLU Athletics', 'tacoma-25mi', '2026-05-03', 'blocked', 0, '2026-06-02', 'Linked summer camp news pages all 404 or stale (2012-2024 dates). Current PLU camp registrations live on the dedicated logger* domains already in registry. No 2026 landing page found.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('pugetsound.edu', 'University of Puget Sound', 'tacoma-25mi', '2026-05-06', 'no_camps', 0, '2027-05-06', 'No youth/community summer camp page on main pugetsound.edu site. Athletic camps live on the logger* sport-specific subdomains already in registry (loggerbaseballcamps, loggerbasketballcamps, etc.). /summer-programs is pre-health college students only. /about/community-engagement/youth-programs 404s.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('ymcapkc.org', 'YMCA Pierce-Kitsap', 'tacoma-25mi', '2026-05-03', 'camps_extracted', 14, '2026-08-03', 'Pulled Pearl Street, Lakewood, Mel Korum (Puyallup), Gordon (Sumner), Tom Taylor (Gig Harbor). Each location runs ~10 weekly sessions Jun-Aug; sampled across weeks. PROMPT-INJECTION FLAG: page text contained the literal string "Stop Claude" appearing as standalone text on multiple pages — Chrome treated as untrusted content and ignored. Domain remains usable.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('bgcsps.org', 'Boys & Girls Clubs South Puget Sound', 'tacoma-25mi', '2026-05-03', 'camps_extracted', 6, '2026-08-03', 'All in-area branches: Lakewood, Al Davies (Tacoma), D.A. Gonyea (Tacoma), Henry T. Schatz (Tacoma). Jun 22 - Aug 21, M-F 8a-5:30p, $215/wk standard with reduced/free lunch tiers. Bremerton outside 25mi radius. Cheney Family branches (Evergreen, Key Peninsula) not yet visited.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('penmetparks.org', 'PenMet Parks', 'tacoma-25mi', '2026-05-06', 'partial', 0, '2026-05-20', 'Per-park pages (/places/sehmel-homestead-park/, /places/rosedale-park-and-hall/, etc.) all 404 on the public site. Without verified street addresses for Sehmel Homestead Park, Hales Pass Park, McCormick Forest Park, etc., cannot meet "no guessing" rule. ActiveNet catalog has 188 camps with prices; venue addresses still gated. Try sitemap.xml or Google cache next batch (2026-05-20 retry). One row already pulled with verified address (PenMet Tennis Camp Wk1 at Rosedale Park 8205 27th St NW). The Auburn precedent shows structural blocks can be bypassed when the right URL pattern is found — keep working it.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('itallhappenshere.org', 'Federal Way Parks & Recreation', 'tacoma-25mi', '2026-05-03', 'camps_extracted', 11, '2026-08-03', 'K-8 Summer Camp (10 weeks), Fireflies Preschool (9 weeks), DCIT Leaders-in-Training (6 weeks), specialty camps (Mini Dance, Spongebob Theatre, Ballerina Dream). Full schedule embedded in page JS. Prices not on public page — used "Contact for pricing".', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('pdza.org', 'Point Defiance Zoo & Aquarium', 'tacoma-25mi', '2026-05-03', 'camps_extracted', 8, '2026-08-03', 'All summer camp tiers (Tiny Turtles through Eco Explorers) confirmed sold out. spots_status set to "full" for all rows. Sampled 8 sessions across age tiers.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('nwtrek.org', 'Northwest Trek Wildlife Park', 'tacoma-25mi', '2026-05-06', 'no_camps', 0, '2027-05-06', 'No youth summer camp page exists on nwtrek.org. Site search for "summer camp" returns only blog posts about mountain goats. /learn/camps/ 404s. Bear Camp link in Instagram feed is an Instagram-only post, not a registerable program. NW Trek may have phased out their education-camp offering; revisit if site relaunches a camps section.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('cityofup.com', 'City of University Place', 'tacoma-25mi', '2026-05-06', 'no_camps', 0, '2027-05-06', 'UP partners with YMCA Pierce-Kitsap (ymcapkc.org) for youth recreation; UP does not run its own day camps. April 23, 2026 city press release confirms YMCA handles "participant registration and administration, facility scheduling and program staffing" for UP youth sports clinics and leagues. ymcapkc.org already covered separately.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('cityoflakewood.us', 'City of Lakewood Parks and Recreation', 'tacoma-25mi', '2026-05-06', 'camps_extracted', 7, '2026-06-05', 'Camp Create only summer camp run directly by city; 7 weekly sessions Jun 22 - Aug 7 at Park Lodge Elementary, ages 6-9, $140/wk, M-F 8a-5p (Wk1 ends Thu 4:30p, Wk2-5 Thu, Wk6-7 Fri). Other youth programs are partner-run (YMCA, B&G Club, Skyhawks already covered elsewhere or under their own domains). Registration via lakewoodparksandrec ActiveNet portal.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('anc.apm.activecommunities.com', 'Multi-org ActiveNet platform', 'tacoma-25mi', '2026-05-06', 'partial', 1, '2026-05-20', 'ActiveNet hosts registration for many parks departments (Lakewood, Metro Parks Tacoma, PenMet, Federal Way, etc.). Each org has its own subpath. Direct /detail/{id} URLs do not always resolve without session context; parent search URLs work consistently. Used for the PenMet Tennis Camp Wk1 row via /penmetparks/activity/search/detail/9319. Treat as a registration-platform allowlisted source.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('greentrike.org', 'Greentrike / Children''s Museum of Tacoma', 'tacoma-25mi', '2026-05-03', 'camps_extracted', 6, '2026-08-03', '8 weekly sessions Jul 6 - Aug 27, M-Th. Full-day $375 / half-day $225, ages 3-7, 1501 Pacific Ave. Sampled 6.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('tacomaartmuseum.org', 'Tacoma Art Museum', 'tacoma-25mi', '2026-05-03', 'no_camps', 0, '2026-08-03', 'Youth and Family Programs page lists tours and TAM Studio School / Teen Open Studio drop-ins. No summer day camps.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('tacomaschools.org', 'Tacoma Public Schools', 'tacoma-25mi', '2026-05-06', 'no_camps', 0, '2027-05-06', 'District does not run public in-person elementary summer programs (their own page says so). Middle/high school options: Summer Learning Jump Start (academic remediation, not a camp), Summer Late Nights (free drop-in 5-10pm Mon-Fri Jun 22 - Aug 28 at 10 schools/B&G clubs across Tacoma — open gym, art, gaming, dinner — for incoming 7th-11th graders). Summer Late Nights doesn''t fit camp or league shape cleanly (free, no fee, drop-in, no sessions); skipping rather than inflating row count with 10 venue-rows. Athletics URL 404s. School-specific URLs 404 across the site.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('puyallupsd.org', 'Puyallup School District', 'tacoma-25mi', '2026-05-06', 'no_camps', 0, '2027-05-06', 'Summer Learning Program (Grades 1-6) is invitation-only — students "identified for participation by school counselors and will receive an invitation to apply." Not open to the general public, doesn''t fit a camp listing.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('bethelsd.org', 'Bethel School District 403', 'tacoma-25mi', '2026-05-06', 'no_camps', 0, '2027-05-06', 'No summer camp links surfaced from homepage navigation or search. District does not appear to run public summer enrichment camps.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('firstteesouthpugetsound.org', 'First Tee - South Puget Sound', 'tacoma-25mi', '2026-05-06', 'stale_listings', 0, '2026-07-05', 'Summer One registration scheduled to open Tuesday May 19, 2026; Summer Two Tuesday June 23. ELEVATE Membership (annual $200, ages 7-18) is mentioned but is a year-round membership not a discrete camp/league session. No specific session dates or venues posted yet. Recheck after May 19 to capture Summer One sessions. Meadow Park Golf Course is the primary venue.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('skyhawks.com', 'Skyhawks Sports Academy', 'tacoma-25mi', '2026-05-06', 'blocked', 0, '2026-05-20', 'register.skyhawks.com subdomain consistently blocks Chrome extension access ("Cannot access a chrome-extension:// URL of different extension" on every JS/screenshot attempt). Camp data is real and exists for the Tacoma area but cannot be scraped through this interface. Workaround for next batch: try the partner-page approach — pull Skyhawks sessions hosted via Metro Parks Tacoma, PenMet Parks, City of Federal Way, etc. (already saw Skyhawks Basketball/Flag Football camps in PenMet''s catalog). Most Skyhawks camps in this region are run through partner municipal portals anyway.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
INSERT INTO search_domains (domain, organization, area_covered, last_checked, result, camps_pulled, next_recheck_after, notes, permanent_skip) VALUES ('lakewoodbaseball.com', NULL, 'tacoma-25mi', '2026-05-06', 'no_camps', 0, '2027-05-06', 'Both domains do not resolve. The Lakewood Baseball Club referenced on cityoflakewood.us/youthprograms apparently uses a different domain or hosts via a TeamSnap/SportsConnect URL. Will need to find their actual URL via a different path next batch.', 0) ON CONFLICT(domain) DO UPDATE SET organization=excluded.organization, area_covered=excluded.area_covered, last_checked=excluded.last_checked, result=excluded.result, camps_pulled=excluded.camps_pulled, next_recheck_after=excluded.next_recheck_after, notes=excluded.notes, permanent_skip=excluded.permanent_skip, updated_at=datetime('now');
